    47→            ScalarArray lowerSky = new ScalarArray(new MCvScalar(Convert.ToInt32(tbH1.Text), Convert.ToInt32(tbS1.Text), Convert.ToInt32(tbV1.Text)));
    48→            ScalarArray upperSky = new ScalarArray(new MCvScalar(Convert.ToInt32(tbH2.Text), Convert.ToInt32(tbS2.Text), Convert.ToInt32(tbV2.Text))); 
    49→
    50→          
    51→            Mat mask = new Mat();
    52→            CvInvoke.InRange(hsv, lowerSky, upperSky, mask);
    53→
    54→          
    55→            srcColor.SetTo(new MCvScalar(255, 255, 255), mask);
    56→
    57→            Mat srcGray = new Mat();
    58→
    59→            CvInvoke.CvtColor(srcColor, srcGray, ColorConversion.Bgr2Gray);
    60→
    61→            Image<Gray, byte> gray = srcGray.ToImage<Gray, byte>();
    62→
    63→            Mat display = srcGray.Clone();
    64→
    65→
    66→            string txtANGLE = @"C:\SPRING_FINDER\ANGLE.txt";
    67→
    68→            string[] lines = File.ReadAllLines(txtANGLE);
    69→
    70→
    71→            tbResult.Text = "";
    72→
    73→            foreach (string line in lines)
    74→            {
    75→                if (string.IsNullOrWhiteSpace(line))
    76→                    continue;
    77→
    78→                string[] angles = line.Split(',');
    79→
    80→
    81→                double startAngle = int.Parse(angles[0].Trim());
    82→                double endAngle = int.Parse(angles[1].Trim());
    83→                int cent_x = int.Parse(angles[2].Trim());
    84→                int cent_y = int.Parse(angles[3].Trim());
    85→                int radius = int.Parse(angles[4].Trim());
    86→                int colorThread = int.Parse(angles[5].Trim());
    87→                int cntThread = int.Parse(angles[6].Trim());
    88→
    89→                Size axes = new Size(radius, radius);
    90→
    91→                Point center = new Point(cent_x, cent_y);
    92→
    93→                int blackCount = 0;
    94→
    95→                for (double angle = startAngle; angle <= endAngle; angle = angle + 0.1)
    96→                {
    97→                    double rad = -angle * Math.PI / 180.0;
    98→
    99→                    int x = (int)(center.X + radius * Math.Cos(rad));
   100→                    int y = (int)(center.Y + radius * Math.Sin(rad)); // y는 위쪽이 -
   101→
   102→                    if (x >= 0 && x < gray.Width && y >= 0 && y < gray.Height)
   103→                    {
   104→
   105→                        byte pixelValue = gray.Data[y, x, 0];
   106→
   107→                        MCvScalar arcColor;
   108→                        arcColor = new MCvScalar(128);
   109→
   110→                        int size = 1;
   111→
   112→                        if (pixelValue < colorThread)
   113→                        {
   114→                            blackCount++;
   115→                            arcColor = new MCvScalar(0);
   116→                            size = 2;
   117→                        }
   118→
   119→                        CvInvoke.Circle(
   120→                                       display,
   121→                                       new Point(x, y),
   122→                                       size,                    // 반지름 (1~2 추천)
   123→                                       arcColor,   // 회색 점
   124→                                       -1                    // 채우기
   125→                                       );
   126→
   127→                    }
   128→                }
   129→
   130→                if (blackCount > cntThread)
   131→                {
   132→                    tbResult.Text = tbResult.Text + "(" + blackCount.ToString() + ")TRUE\r\n";
   133→                }
   134→                else
   135→                {
   136→                    tbResult.Text = tbResult.Text + "(" + blackCount.ToString() + ")FALSE\r\n";
   137→                }
   138→
   139→
   140→            }
   141→
   142→            // 7. 화면에 표시
   143→            imageBox1.Image = display;
   144→
   145→        }
